use chrono::{DateTime, Duration, Utc};
use std::fmt;

/// Represents a task with metadata.
#[derive(Debug, Clone, PartialEq)]
pub struct Task {
    pub id: u64,
    pub title: String,
    pub completed: bool,
    pub due_date: Option<DateTime<Utc>>,
    pub tags: Vec<String>,
}

/// Custom error type for TaskManager operations.
#[derive(Debug)]
pub enum TaskError {
    EmptyTitle,
    TaskNotFound(u64),
}

impl fmt::Display for TaskError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            TaskError::EmptyTitle => write!(f, "Task title cannot be empty"),
            TaskError::TaskNotFound(id) => write!(f, "Task with ID {} not found", id),
        }
    }
}

impl std::error::Error for TaskError {}

/// Manages a collection of tasks with auto-incrementing IDs.
pub struct TaskManager {
    tasks: Vec<Task>,
    next_id: u64,
}

impl TaskManager {
    /// Creates a new, empty TaskManager.
    pub fn new() -> Self {
        Self {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    /// Adds a new task to the manager.
    /// Returns the created task, or an error if validation fails.
    pub fn add_task(
        &mut self,
        title: &str,
        due_date: Option<DateTime<Utc>>,
        tags: Vec<String>,
    ) -> Result<Task, TaskError> {
        if title.trim().is_empty() {
            return Err(TaskError::EmptyTitle);
        }

        let task = Task {
            id: self.next_id,
            title: title.to_string(),
            completed: false,
            due_date,
            tags,
        };

        self.next_id += 1;
        self.tasks.push(task.clone());
        Ok(task)
    }

    /// Marks a task as completed by its ID.
    /// Returns Ok(()) if found and updated, or an error if not found.
    pub fn complete_task(&mut self, task_id: u64) -> Result<(), TaskError> {
        if let Some(task) = self.tasks.iter_mut().find(|t| t.id == task_id) {
            task.completed = true;
            Ok(())
        } else {
            Err(TaskError::TaskNotFound(task_id))
        }
    }

    /// Returns a list of references to overdue, incomplete tasks.
    pub fn get_overdue(&self) -> Vec<&Task> {
        let now = Utc::now();
        self.tasks
            .iter()
            .filter(|t| {
                t.due_date
                    .as_ref()
                    .map_or(false, |due| !t.completed && due < &now)
            })
            .collect()
    }
}

// -----------------------------------------------------------------------------
// Example usage & demonstration
// -----------------------------------------------------------------------------
fn main() {
    let mut manager = TaskManager::new();

    // 1. Add tasks
    let task1 = manager
        .add_task("Write Rust code", None, vec!["dev".to_string()])
        .unwrap();
    println!("✅ Created task: {:?}", task1);

    // Add a task with a past due date to test overdue logic
    let past_due = Utc::now() - Duration::days(1);
    manager
        .add_task("Fix critical bug", Some(past_due), vec!["urgent".to_string()])
        .unwrap();

    // 2. Get overdue tasks
    let overdue = manager.get_overdue();
    println!("⏳ Overdue tasks: {:?}", overdue);

    // 3. Complete a task
    match manager.complete_task(task1.id) {
        Ok(()) => println!("🎉 Task {} marked as completed!", task1.id),
        Err(e) => eprintln!("❌ {}", e),
    }

    // 4. Error handling demonstration
    match manager.add_task("", None, vec![]) {
        Ok(_) => unreachable!(),
        Err(e) => eprintln!("🛑 Expected validation error: {}", e),
    }

    match manager.complete_task(999) {
        Ok(()) => unreachable!(),
        Err(e) => eprintln!("🛑 Expected lookup error: {}", e),
    }
}
