        title: String,
        due_date: Option<DateTime<Utc>>,
        tags: impl IntoIterator<Item = String>,
    ) -> &Task {
        let task = Task::new(
            self.next_id,
            title,
            due_date,
            tags.into_iter().collect(),
        );

        self.next_id += 1;
        self.tasks.push(task);

        // Return a reference to the newly added task
        self.tasks.last().unwrap()
