        let now = Utc::now();
        self.tasks
            .iter()
            .filter(|task| task.is_overdue(&now))
            .collect()
    }

    /// Returns all tasks (immutable reference)
    fn tasks(&self) -> &[Task] {
        &self.tasks
    }

    /// Finds a task by ID (mutable reference)
